    vm.shrImm(VReg.V0, VReg.S1, 48);
    vm.movImm(VReg.V2, 32764);
    vm.cmp(VReg.V0, VReg.V2);
    const arg1NotString = "_strcmp_arg1_not_string";
    const arg1Done = "_strcmp_arg1_done";
    const arg1IsNanboxed = "_strcmp_arg1_is_nanboxed";
