  /**
   * NFA 匹配 (Thompson 构造)
   * A0 = NFA 起始状态
   * A1 = 输入字符串
   * A2 = 起始位置
   * A3 = flags (g=1, i=2, m=4, s=8, u=16, y=32)
   * RET = 1 (匹配) 或 0 (不匹配)
   */
  generateNFAMatch() {
    const vm = this.vm;
    const FLAG_IGNORE_CASE = 2;
    vm.label("_nfa_match");
    vm.prologue(64, [VReg.S0, VReg.S1, VReg.S2, VReg.S3, VReg.S4]);
    vm.mov(VReg.S0, VReg.A0);
    vm.mov(VReg.S1, VReg.A1);
    vm.mov(VReg.S2, VReg.A2);
    vm.mov(VReg.S3, VReg.A3);
    const matchLoop = "_nfa_match_loop";
    const matchChar = "_nfa_match_char";
    const matchCharCompare = "_nfa_match_char_compare";
    const matchCharOk = "_nfa_match_char_ok";
    const matchAny = "_nfa_match_any";
    const matchSplit = "_nfa_match_split";
    const matchSuccess = "_nfa_match_success";
    const matchFail = "_nfa_match_fail";
    vm.label(matchLoop);
    vm.cmpImm(VReg.S0, 0);
    vm.jeq(matchFail);
    vm.load(VReg.V0, VReg.S0, 0);
    vm.cmpImm(VReg.V0, NFA_MATCH);
    vm.jeq(matchSuccess);
    vm.cmpImm(VReg.V0, NFA_CHAR);
    vm.jeq(matchChar);
    vm.cmpImm(VReg.V0, NFA_ANY);
    vm.jeq(matchAny);
    vm.cmpImm(VReg.V0, NFA_SPLIT);
    vm.jeq(matchSplit);
    vm.cmpImm(VReg.V0, NFA_CHAR_CLASS);
    vm.jeq("_nfa_match_char_class");
    vm.jmp(matchFail);
    vm.label(matchChar);
    vm.add(VReg.V1, VReg.S1, VReg.S2);
    vm.loadByte(VReg.V2, VReg.V1, 0);
    vm.cmpImm(VReg.V2, 0);
    vm.jeq(matchFail);
    vm.load(VReg.V3, VReg.S0, 8);
    vm.andImm(VReg.V4, VReg.S3, FLAG_IGNORE_CASE);
    vm.cmpImm(VReg.V4, 0);
    vm.jeq(matchCharCompare);
    vm.cmpImm(VReg.V2, 65);
    vm.jlt(matchCharCompare + "_v3");
    vm.cmpImm(VReg.V2, 90);
    vm.jgt(matchCharCompare + "_v3");
    vm.addImm(VReg.V2, VReg.V2, 32);
    vm.label(matchCharCompare + "_v3");
    vm.cmpImm(VReg.V3, 65);
    vm.jlt(matchCharCompare);
    vm.cmpImm(VReg.V3, 90);
    vm.jgt(matchCharCompare);
    vm.addImm(VReg.V3, VReg.V3, 32);
    vm.label(matchCharCompare);
    vm.cmp(VReg.V2, VReg.V3);
    vm.jne(matchFail);
    vm.label(matchCharOk);
    vm.load(VReg.S0, VReg.S0, 16);
    vm.addImm(VReg.S2, VReg.S2, 1);
    vm.jmp(matchLoop);
    vm.label(matchAny);
    vm.add(VReg.V1, VReg.S1, VReg.S2);
    vm.loadByte(VReg.V2, VReg.V1, 0);
    vm.cmpImm(VReg.V2, 0);
    vm.jeq(matchFail);
    vm.cmpImm(VReg.V2, 10);
    vm.jeq(matchFail);
    vm.load(VReg.S0, VReg.S0, 16);
    vm.addImm(VReg.S2, VReg.S2, 1);
    vm.jmp(matchLoop);
    vm.label(matchSplit);
    vm.load(VReg.V4, VReg.S0, 16);
    vm.push(VReg.S0);
    vm.push(VReg.S2);
    vm.mov(VReg.A0, VReg.V4);
    vm.mov(VReg.A1, VReg.S1);
    vm.mov(VReg.A2, VReg.S2);
    vm.mov(VReg.A3, VReg.S3);
    vm.call("_nfa_match");
    vm.pop(VReg.S2);
    vm.pop(VReg.S0);
    vm.cmpImm(VReg.RET, 1);
    vm.jeq(matchSuccess);
    vm.load(VReg.S0, VReg.S0, 24);
    vm.jmp(matchLoop);
    vm.label("_nfa_match_char_class");
    vm.add(VReg.V1, VReg.S1, VReg.S2);
    vm.loadByte(VReg.V2, VReg.V1, 0);
    vm.cmpImm(VReg.V2, 0);
    vm.jeq(matchFail);
    vm.load(VReg.V3, VReg.S0, 8);
    vm.shrImm(VReg.V4, VReg.V2, 3);
    vm.andImm(VReg.V5, VReg.V2, 7);
    vm.movImm(VReg.V6, 1);
    vm.shl(VReg.V6, VReg.V6, VReg.V5);
    vm.add(VReg.V7, VReg.V3, VReg.V4);
    vm.loadByte(VReg.A0, VReg.V7, 0);
    vm.and(VReg.A0, VReg.A0, VReg.V6);
    vm.cmpImm(VReg.A0, 0);
    vm.jeq(matchFail);
    vm.load(VReg.S0, VReg.S0, 16);
    vm.addImm(VReg.S2, VReg.S2, 1);
    vm.jmp(matchLoop);
    vm.label(matchSuccess);
    vm.movImm(VReg.RET, 1);
    vm.epilogue([VReg.S0, VReg.S1, VReg.S2, VReg.S3, VReg.S4], 64);
    vm.label(matchFail);
    vm.movImm(VReg.RET, 0);
    vm.epilogue([VReg.S0, VReg.S1, VReg.S2, VReg.S3, VReg.S4], 64);
  }
  /**
   * exec() 方法 - 返回匹配数组或 null
   * A0 = RegExp 对象
   * A1 = 输入字符串
   * RET = 结果数组或 0 (null)
   */
  generateExec() {
    const vm = this.vm;
    vm.label("_regexp_exec_full");
    vm.prologue(48, [VReg.S0, VReg.S1, VReg.S2, VReg.S3, VReg.S4]);
    vm.mov(VReg.S0, VReg.A0);
    vm.mov(VReg.S1, VReg.A1);
    vm.load(VReg.S2, VReg.S0, 8);
    vm.mov(VReg.A0, VReg.S2);
    vm.call("_regexp_parse");
    vm.mov(VReg.S3, VReg.RET);
    vm.cmpImm(VReg.S3, 0);
    vm.jeq("_regexp_exec_full_null");
    vm.mov(VReg.A0, VReg.S1);
    vm.call("_strlen");
    vm.mov(VReg.S4, VReg.RET);
    vm.movImm(VReg.V5, 0);
    const searchLoop = "_regexp_exec_search";
    const searchDone = "_regexp_exec_found";
    const searchEnd = "_regexp_exec_not_found";
    vm.label(searchLoop);
    vm.cmp(VReg.V5, VReg.S4);
    vm.jgt(searchEnd);
    vm.mov(VReg.A0, VReg.S3);
    vm.mov(VReg.A1, VReg.S1);
    vm.mov(VReg.A2, VReg.V5);
    vm.push(VReg.V5);
    vm.call("_nfa_match");
    vm.pop(VReg.V5);
    vm.cmpImm(VReg.RET, 1);
    vm.jeq(searchDone);
    vm.addImm(VReg.V5, VReg.V5, 1);
    vm.jmp(searchLoop);
    vm.label(searchDone);
    vm.movImm(VReg.A0, 1);
    vm.call("_array_new_with_size");
    vm.mov(VReg.S4, VReg.RET);
    vm.add(VReg.V0, VReg.S1, VReg.V5);
    vm.mov(VReg.A0, VReg.S4);
    vm.movImm(VReg.A1, 0);
    vm.mov(VReg.A2, VReg.V0);
    vm.call("_array_set");
    vm.mov(VReg.RET, VReg.S4);
    vm.epilogue([VReg.S0, VReg.S1, VReg.S2, VReg.S3, VReg.S4], 48);
    vm.label("_regexp_exec_full_null");
    vm.label(searchEnd);
    vm.movImm(VReg.RET, 0);
    vm.epilogue([VReg.S0, VReg.S1, VReg.S2, VReg.S3, VReg.S4], 48);
  }
