    vm.mov(VReg.A0, VReg.S3);
    vm.mov(VReg.A1, VReg.S1);
    vm.mov(VReg.A2, VReg.V2);
    vm.mov(VReg.A3, VReg.S4);
    vm.push(VReg.V2);
    vm.call("_nfa_match");
    vm.pop(VReg.V2);
    vm.cmpImm(VReg.RET, 1);
