    const vm = this.vm;
    vm.label("_iterator_result");
    vm.prologue(32, [VReg.S0, VReg.S1, VReg.S2]);
    vm.mov(VReg.S0, VReg.A0);
    vm.mov(VReg.S1, VReg.A1);
