    vm.store(VReg.S2, 8, VReg.V1);
    vm.movImm(VReg.V1, 0);
    vm.store(VReg.S2, 16, VReg.V1);
    vm.lea(VReg.V1, "_str_value");
    vm.store(VReg.S2, 24, VReg.V1);
    vm.store(VReg.S2, 32, VReg.S0);
