      if (isMac) return isArm64 ? Syscall.MACOS_RMDIR_ARM64 : Syscall.MACOS_RMDIR_X64;
      return isArm64 ? Syscall.LINUX_RMDIR_ARM64 : Syscall.LINUX_RMDIR;
