    vm.shrImm(VReg.S3, VReg.S1, 48);
    vm.movImm(VReg.V0, NANBOX_STRING_TAG);
    vm.cmp(VReg.S2, VReg.V0);
    vm.jeq("_js_add_strconcat");
    vm.cmp(VReg.S3, VReg.V0);
    vm.jeq("_js_add_strconcat");
