    vm.store(VReg.V0, 0, VReg.S2);
    vm.lea(VReg.V0, "_old_alloc_ptr");
    vm.store(VReg.V0, 0, VReg.S2);
    vm.addImm(VReg.V1, VReg.S2, OLD_GEN_INITIAL_SIZE);
