    vm.store(VReg.V0, 0, VReg.V2);
    vm.movImm(VReg.V3, 0);
    vm.store(VReg.V1, HDR_FLAGS_SIZE2, VReg.V3);
    vm.store(VReg.V1, HDR_NEXT2, VReg.V3);
